(print ord=1,Metric='🗓️ Window (hrs of data)',Value=tostring(round(span,2))),
(print ord=2,Metric='📈 Projected monthly spend',Value=iff(ready,strcat('$',tostring(round(proj,0))),'accruing…')),
(print ord=3,Metric='🎯 Monthly budget',Value=strcat('$',tostring(round(budget,0)))),
(print ord=4,Metric='📊 % of budget',Value=iff(ready,strcat(tostring(round(100.0*proj/budget,0)),'%'),'—'))
|order by ord asc|project Metric,Value
